UPDATE tracks SET planet = jsonb_set(coalesce(planet,'{}'::jsonb), '{analysis}', $j${"summary":"The song captures a melancholic yet ethereal journey through time where moments dissolve like mist over a river, blending gritty noir aesthetics with dreamy liberation from reality.","overallMood":"ethereal and cinematic","themes":["Melancholy acceptance of passing time","Ethereal escapism","Noir atmosphere vs. natural beauty","Intimacy in stillness"],"palette":["#2C3539","#8B0000","#D4AF37","#E6E6FA"],"sections":[{"name":"Intro","emotion":"Hopeful anticipation","intensity":0.76,"colorHint":"#f5f5dc","start":0.03},{"name":"Verse 1","emotion":"Slow drifting melancholy","intensity":0.63,"colorHint":"#708090","start":45.92},{"name":"Pre-Chorus","emotion":"Urgent tenderness","intensity":0.6,"colorHint":"#d2b48c","start":56.96},{"name":"Chorus","emotion":"Transcendent release","intensity":0.54,"colorHint":"#e3f7ff","start":67.88},{"name":"Verse 2","emotion":"Repetitive trance state","intensity":0.15,"colorHint":"#556b2f","start":131.5},{"name":"Bridge","emotion":"Spiritual ascent","intensity":0.24,"colorHint":"#fffae3","start":160.9}],"keywords":[{"word":"drift","emotion":"weightless sorrow","imageryPrompt":"A leaf floating on a dark river under moonlight, slow motion water ripples reflecting distorted city lights."},{"word":"gray","emotion":"melancholic fading","imageryPrompt":"Black and white film grain overlaying colorful clouds dissolving into monochrome mist over a foggy dockside street."},{"word":"breathe","emotion":"relief and calm","imageryPrompt":"Close-up of chest rising against the night sky, soft glowing particles floating in air like dust motes in sunlight."},{"word":"alive","emotion":"vibrant connection","imageryPrompt":"Flowers blooming rapidly on a cracked concrete rooftop with vibrant green stems contrasting against gritty urban background."},{"word":"fade","emotion":"gentle disappearance","imageryPrompt":"A silhouette of an old steamboat drifting into thick fog until it becomes indistinguishable from the surrounding mist."},{"word":"light","emotion":"divine arrival","imageryPrompt":"Beams of golden sunlight piercing through heavy storm clouds illuminating a dusty room filled with floating dust particles."}]}$j$::jsonb) WHERE id = 'days-drift-by' AND planet->'analysis' IS NULL;

